class Solution:
    def productExceptSelf(self, nums):
        n = len(nums)
        res = [1] * n
        pref = 1
        for i in range(n):
            res[i] = pref
            pref *= nums[i]
        suf = 1
        for i in range(n - 1, -1, -1):
            res[i] *= suf
            suf *= nums[i]
        return res

