var productExceptSelf = function(nums) {
    const n = nums.length;
    const res = new Array(n).fill(1);
    let pref = 1;
    for (let i = 0; i < n; i++) {
        res[i] = pref;
        pref *= nums[i];
    }
    let suf = 1;
    for (let i = n - 1; i >= 0; i--) {
        res[i] *= suf;
        suf *= nums[i];
    }
    return res;
};
